  // Read fields from "Consultar card"
  const fields = $('Consultar card').item.json.data?.card?.fields ?? [];

  // Find field by field.id or indexName
  const get = (id) => fields.find(x => (x.field?.id ?? x.indexName ?? '') === id);

  const clean = (s) => String(s ?? '').trim();
  const f = get('auto_historico_de_redes');

  if (!f) return [];

  // This field is long text in the format: "id1,id2,id3,..."
  const raw = clean(f.value);

  if (!raw) return [];

  // Split by comma, trim, remove empties
  return raw
    .split(',')
    .map(x => clean(x))
    .filter(x => x.length > 0);
})() }}

